using System.Diagnostics;
using System.Globalization;
using CSharpDB.Storage.Paging;

namespace CSharpDB.Benchmarks.Infrastructure;

internal static class CommitPathDiagnosticsFormatter
{
    public static string BuildSummary(CommitPathDiagnosticsSnapshot diagnostics)
    {
        double maxPendingCommitKiB = diagnostics.MaxPendingCommitBytes / 1024.0;
        return string.Create(
            CultureInfo.InvariantCulture,
            $"walAppends={diagnostics.WalAppendCount}, avgWalAppendMs={AverageMilliseconds(diagnostics.WalAppendTicks, diagnostics.WalAppendCount):F3}, explicitCommitLockWaits={diagnostics.ExplicitCommitLockWaitCount}, avgExplicitCommitLockWaitMs={AverageMilliseconds(diagnostics.ExplicitCommitLockWaitTicks, diagnostics.ExplicitCommitLockWaitCount):F3}, explicitCommitLockHolds={diagnostics.ExplicitCommitLockHoldCount}, avgExplicitCommitLockHoldMs={AverageMilliseconds(diagnostics.ExplicitCommitLockHoldTicks, diagnostics.ExplicitCommitLockHoldCount):F3}, explicitConflictResolutions={diagnostics.ExplicitConflictResolutionCount}, avgExplicitConflictResolutionMs={AverageMilliseconds(diagnostics.ExplicitConflictResolutionTicks, diagnostics.ExplicitConflictResolutionCount):F3}, leafRebases={diagnostics.ExplicitLeafRebaseAttemptCount}/{diagnostics.ExplicitLeafRebaseSuccessCount}/{diagnostics.ExplicitLeafRebaseStructuralRejectCount}/{diagnostics.ExplicitLeafRebaseCapacityRejectCount}, leafRejectReasons={diagnostics.ExplicitLeafRebaseRejectNonInsertOnlyCount}/{diagnostics.ExplicitLeafRebaseRejectDuplicateKeyCount}/{diagnostics.ExplicitLeafRebaseRejectSplitFallbackPreconditionCount}/{diagnostics.ExplicitLeafRebaseRejectSplitFallbackShapeCount}/{diagnostics.ExplicitLeafRebaseRejectOtherCount}, leafSplitPreconditions={diagnostics.ExplicitLeafRebaseRejectSplitFallbackMissingTraversalCount}/{diagnostics.ExplicitLeafRebaseRejectSplitFallbackDirtyAncestorCount}/{diagnostics.ExplicitLeafRebaseRejectSplitFallbackParentBoundaryCount}/{diagnostics.ExplicitLeafRebaseRejectSplitFallbackTargetPageDirtyCount}, dirtyParentRecoveries={diagnostics.ExplicitLeafRebaseRejectDirtyParentMissingParentPageCount}/{diagnostics.ExplicitLeafRebaseRejectDirtyParentTransactionLeafNotSplitCount}/{diagnostics.ExplicitLeafRebaseRejectDirtyParentBaseBoundaryMissingCount}/{diagnostics.ExplicitLeafRebaseRejectDirtyParentInsertionShapeCount}/{diagnostics.ExplicitLeafRebaseRejectDirtyParentInsertionMismatchCount}/{diagnostics.ExplicitLeafRebaseRejectDirtyParentMissingLocalRightPageCount}/{diagnostics.ExplicitLeafRebaseRejectDirtyParentLocalSplitShapeCount}/{diagnostics.ExplicitLeafRebaseRejectDirtyParentRebaseFailureCount}, dirtyParentDescribeMatches={diagnostics.ExplicitLeafRebaseRejectDirtyParentDescribedInsertionMatchCount}, interiorRebases={diagnostics.ExplicitInteriorRebaseAttemptCount}/{diagnostics.ExplicitInteriorRebaseSuccessCount}/{diagnostics.ExplicitInteriorRebaseStructuralRejectCount}/{diagnostics.ExplicitInteriorRebaseCapacityRejectCount}, explicitPendingCommitWaits={diagnostics.ExplicitPendingCommitWaitCount}, avgExplicitPendingCommitWaitMs={AverageMilliseconds(diagnostics.ExplicitPendingCommitWaitTicks, diagnostics.ExplicitPendingCommitWaitCount):F3}, explicitHeaderPreparations={diagnostics.ExplicitHeaderPreparationCount}, avgExplicitHeaderPreparationMs={AverageMilliseconds(diagnostics.ExplicitHeaderPreparationTicks, diagnostics.ExplicitHeaderPreparationCount):F3}, explicitPendingCommitReservations={diagnostics.ExplicitPendingCommitReservationCount}, avgExplicitPendingCommitReservationMs={AverageMilliseconds(diagnostics.ExplicitPendingCommitReservationTicks, diagnostics.ExplicitPendingCommitReservationCount):F3}, durableBatchWindowWaits={diagnostics.DurableBatchWindowWaitCount}, avgDurableBatchWindowWaitMs={AverageMilliseconds(diagnostics.DurableBatchWindowWaitTicks, diagnostics.DurableBatchWindowWaitCount):F3}, pendingCommitWrites={diagnostics.PendingCommitWriteCount}, avgPendingCommitWriteMs={AverageMilliseconds(diagnostics.PendingCommitWriteTicks, diagnostics.PendingCommitWriteCount):F3}, pendingCommitDrains={diagnostics.PendingCommitDrainCount}, avgPendingCommitDrainMs={AverageMilliseconds(diagnostics.PendingCommitDrainTicks, diagnostics.PendingCommitDrainCount):F3}, bufferedFlushes={diagnostics.BufferedFlushCount}, avgBufferedFlushMs={AverageMilliseconds(diagnostics.BufferedFlushTicks, diagnostics.BufferedFlushCount):F3}, durableFlushes={diagnostics.DurableFlushCount}, avgDurableFlushMs={AverageMilliseconds(diagnostics.DurableFlushTicks, diagnostics.DurableFlushCount):F3}, publishBatches={diagnostics.PublishBatchCount}, avgPublishBatchMs={AverageMilliseconds(diagnostics.PublishBatchTicks, diagnostics.PublishBatchCount):F3}, finalizations={diagnostics.FinalizeCommitCount}, avgFinalizeMs={AverageMilliseconds(diagnostics.FinalizeCommitTicks, diagnostics.FinalizeCommitCount):F3}, checkpointDecisions={diagnostics.CheckpointDecisionCount}, avgCheckpointDecisionMs={AverageMilliseconds(diagnostics.CheckpointDecisionTicks, diagnostics.CheckpointDecisionCount):F3}, backgroundCheckpointStarts={diagnostics.BackgroundCheckpointStartCount}, btreeLeafSplits={diagnostics.BTreeLeafSplitCount}, btreeRightEdgeLeafSplits={diagnostics.BTreeRightEdgeLeafSplitCount}, btreeInteriorInserts={diagnostics.BTreeInteriorInsertCount}, btreeRightEdgeInteriorInserts={diagnostics.BTreeRightEdgeInteriorInsertCount}, btreeInteriorSplits={diagnostics.BTreeInteriorSplitCount}, btreeRightEdgeInteriorSplits={diagnostics.BTreeRightEdgeInteriorSplitCount}, btreeRootSplits={diagnostics.BTreeRootSplitCount}, maxPendingCommits={diagnostics.MaxPendingCommitCount}, maxPendingCommitKiB={maxPendingCommitKiB:F1}");
    }

    public static double AverageMilliseconds(long ticks, long count)
    {
        if (ticks <= 0 || count <= 0)
            return 0;

        return ticks * 1000.0 / Stopwatch.Frequency / count;
    }
}
